import { v4 as uuidv4 } from "uuid";
import RepositoryDefaults from "./RepositoryDefaults";
import RepositoryUrls from "./RepositoryUrls";
import { FetchError } from "./RepositoryErrors";
import React from "react";
import "./Repository.css";

export default class Repository {
  constructor(data = {}) {
    this.id = data.id || uuidv4();
    this.name = data.name || "unknown";
    this.fullName = data.full_name || "";
    this.description = data.description || "";
    this.url = data.html_url || "";
    this.cloneUrl = data.clone_url || "";
    this.owner = data.owner?.login || "unknown";
    this.ownerUrl = data.owner?.html_url || "";
    this.ownerAvatar = data.owner?.avatar_url || RepositoryDefaults.AVATAR;
    this.license = data.license?.name || RepositoryDefaults.LICENSE;
    this.visibility = data.private ? "private" : RepositoryDefaults.VISIBILITY;
    this.status = data.archived ? "archived" : data.fork ? "fork" : RepositoryDefaults.STATUS;

    this.creationDate = data.created_at ? new Date(data.created_at) : new Date();
    this.lastUpdate = data.updated_at ? new Date(data.updated_at) : new Date();
    this.stars = data.stargazers_count || 0;
    this.forks = data.forks_count || 0;
    this.issuesUrl = `${this.url}/issues`;
    this.documentationLink = data.has_wiki ? `${this.url}/wiki` : null;
    this.liveDemoLink = data.liveDemoLink || RepositoryDefaults.LIVE_DEMO;
    this.screenshots = data.screenshots || RepositoryDefaults.SCREENSHOTS;

    this.languages = [];
    this.readme = null;
    this.readmeRawUrl = "";
    this.contributorsUrl = data.contributors_url || "";
    this.contributors = [];
    this.topics = []; // GitHub topics / tags
    this.openIssues = data.open_issues_count || 0;
    this.watchers = data.watchers_count || 0;

    this.coverImage = data.coverImage || RepositoryDefaults.COVER_IMAGE;
  }

  copyGitClone() {
    navigator.clipboard.writeText(`git clone ${this.cloneUrl}`);
    alert(`Git clone URL copied:\n${this.cloneUrl}`);
  }

  /** FETCH METHODS **/

  // fetch contributors
  async fetchContributors(signal) {
    if (!this.contributorsUrl) return [];
    const res = await fetch(this.contributorsUrl, { signal });
    if (!res.ok) throw new FetchError("contributors", res.status);
    const json = await res.json();
    this.contributors = json.map(c => ({
      login: c.login,
      url: c.html_url,
      avatar: c.avatar_url
    }));
    return this.contributors;
  }

  // fetch README
  async fetchReadme(signal) {
    const urls = [
      RepositoryUrls.README_MASTER(this.fullName),
      RepositoryUrls.README_MAIN(this.fullName),
    ];
    for (const url of urls) {
      const res = await fetch(url, { signal });
      if (res.ok) {
        this.readme = await res.text();
        this.readmeRawUrl = url;
        return this.readme;
      }
    }
    throw new FetchError("README", 404, "README not found");
  }

  // fetch languages
  async fetchLanguages(signal) {
    if (!this.fullName) return [];
    const url = `https://api.github.com/repos/${this.fullName}/languages`;
    const res = await fetch(url, { signal });
    if (!res.ok) throw new FetchError("languages", res.status);
    const json = await res.json();
    this.languages = Object.keys(json);
    return this.languages;
  }

  // fetch topics (GitHub repository tags)
  async fetchTopics(signal) {
    if (!this.fullName) return [];
    const url = `https://api.github.com/repos/${this.fullName}/topics`;
    const res = await fetch(url, { 
      headers: { Accept: "application/vnd.github.mercy-preview+json" },
      signal
    });
    if (!res.ok) throw new FetchError("topics", res.status);
    const json = await res.json();
    this.topics = json.names || [];
    return this.topics;
  }

  // fetch all metadata at once
  async fetchAll(signal) {
    await Promise.all([
      this.fetchLanguages(signal),
      this.fetchContributors(signal),
      this.fetchTopics(signal),
      this.fetchReadme(signal).catch(() => null)
    ]);
  }

  getReadmeDownloadUrl() {
    return this.readmeRawUrl || RepositoryUrls.README_MAIN(this.fullName);
  }

  renderCard() {
    return (
      <div key={this.id} className="repo-card">
        <img src={this.coverImage} alt={`${this.name} cover`} className="repo-cover" />

        <div className="repo-body">
          <div className="repo-header">
            <img src={this.ownerAvatar} alt={this.owner} className="repo-owner-avatar" />
            <a href={this.url} target="_blank" rel="noopener noreferrer" className="repo-name">
              {this.name}
            </a>
          </div>

          {this.description && <p className="repo-description">{this.description}</p>}

          {this.languages.length > 0 && (
            <div className="repo-languages">
              {this.languages.map(lang => (
                <span key={lang} className="repo-language">{lang}</span>
              ))}
            </div>
          )}

          {this.topics.length > 0 && (
            <div className="repo-topics">
              {this.topics.map(topic => (
                <span key={topic} className="repo-topic">{topic}</span>
              ))}
            </div>
          )}

          <div className="repo-actions">
            <button onClick={() => this.copyGitClone()}>Copy git clone</button>
            {this.documentationLink && (
              <a href={this.documentationLink} target="_blank" rel="noopener noreferrer">
                Wiki / Docs
              </a>
            )}
          </div>
        </div>
      </div>
    );
  }

  static async fetchAllByUsername(username, signal) {
    const res = await fetch(`https://api.github.com/users/${username}/repos`, { signal });
    if (!res.ok) throw new FetchError("repositories", res.status);
    const json = await res.json();

    const repos = await Promise.all(
      json.map(async data => {
        const repo = new Repository(data);
        await repo.fetchAll(signal).catch(() => null); // fetch all metadata
        return repo;
      })
    );

    return repos;
  }
}
